// JavaScript Connection Code
const socket = io('http://localhost:5000', {
  query: { token: 'YOUR_ACCESS_TOKEN' },
  transports: ['websocket', 'polling']
});

socket.on('connect', () => {
  console.log('Connected to server');
});

socket.on('auth_error', (error) => {
  console.error('Authentication failed:', error);
});

// Emit event
socket.emit('get_online_users');

// Listen for response
socket.on('online_users_list', (data) => {
  console.log('Online users:', data.users);
  // { users: ["user-id-1", "user-id-2"], timestamp: 1713607200000 }
});

// Listen for user coming online
socket.on('user_online', (data) => {
  console.log(`${data.userId} is now online`);
  // { userId: "user-id", timestamp: 1713607200000 }
});

// Listen for user going offline
socket.on('user_offline', (data) => {
  console.log(`${data.userId} went offline`);
  // { userId: "user-id", timestamp: 1713607200000 }
});

// Send a message
socket.emit(
  'send_message',
  {
    recipientId: 'recipient-user-id',
    text: 'Hello! How are you?',
    timestamp: Date.now()
  },
  (response) => {
    if (response.status === 'sent') {
      console.log('Message sent with ID:', response.messageId);
    } else {
      console.error('Failed to send:', response.message);
    }
  }
);

// Listen for incoming messages
socket.on('receive_message', (data) => {
  console.log(`Message from ${data.senderId}: ${data.text}`);
  // { messageId, senderId, text, timestamp }

  // Auto-send read receipt
  socket.emit('message_read', {
    messageId: data.messageId,
    senderId: data.senderId
  });
});

// Send read receipt
socket.emit('message_read', {
  messageId: 'message-uuid',
  senderId: 'sender-user-id'
});

// Listen for read receipts on your messages
socket.on('read_receipt', (data) => {
  console.log(`Message ${data.messageId} read by ${data.readBy}`);
  // { messageId, readBy, readAt: timestamp }
});

// Emit when user starts typing
socket.emit('user_typing', {
  recipientId: 'recipient-user-id'
});

// Emit when user stops typing (on blur or after delay)
socket.emit('user_stopped_typing', {
  recipientId: 'recipient-user-id'
});

// Listen for typing indicator
socket.on('recipient_typing', (data) => {
  console.log(`${data.senderId} is typing...`);
  // { senderId }
});

// Listen for stopped typing
socket.on('recipient_stopped_typing', (data) => {
  console.log(`${data.senderId} stopped typing`);
  // { senderId }
});

// Listen for message errors
socket.on('message_error', (error) => {
  console.error('Message error:', error);
  // Recipient offline, message too long, etc.
});

// Listen for general socket errors
socket.on('error', (error) => {
  console.error('Socket error:', error);
});

// Listen for authentication errors
socket.on('auth_error', (error) => {
  console.error('Authentication error:', error);
  // Invalid token, expired token, etc.
});

// Listen for disconnection
socket.on('disconnect', () => {
  console.log('Disconnected from server');
});

// Listen for connection errors
socket.on('connect_error', (error) => {
  console.error('Connection error:', error);
});

// STEP 1: Register User A
const registerUserA = async () => {
  const response = await fetch('http://localhost:5000/api/auth/register', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      name: 'Alice',
      email: 'alice@example.com',
      password: 'SecurePass123'
    })
  });
  return await response.json();
};

// STEP 2: Register User B
const registerUserB = async () => {
  const response = await fetch('http://localhost:5000/api/auth/register', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      name: 'Bob',
      email: 'bob@example.com',
      password: 'SecurePass123'
    })
  });
  return await response.json();
