  console.log('Received:', data.text);

  // Auto-send read receipt
  socketB.emit('message_read', {
    messageId: data.messageId,
    senderId: data.senderId
  });
});

// STEP 9: User A receives read receipt
socketA.on('read_receipt', (data) => {
  console.log('Message read at:', new Date(data.readAt));
});
